#include <iostream>
using namespace std;

int main() {
    int a = 3;   // 0011
    int b = 5;   // 0101

    cout << "a & b = " << (a & b) << endl;  // 1

    // 判断奇偶
    int n = 10;
    if ((n & 1) == 0) {
        cout << n << " 是偶数" << endl;
    }

    // 清零
    int x = 100;
    x = x & 0;
    cout << "清零后：" << x << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int a = 3;   // 0011
    int b = 5;   // 0101

    cout << "a | b = " << (a | b) << endl;  // 7

    // 设置低4位为1
    int x = 10;  // 1010
    x = x | 0xF;
    cout << "设置后：" << x << endl;  // 15

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int a = 3;   // 0011
    int b = 5;   // 0101

    cout << "a ^ b = " << (a ^ b) << endl;  // 6

    // 交换两个数
    int x = 10, y = 20;
    cout << "交换前：x=" << x << ", y=" << y << endl;
    x = x ^ y;
    y = x ^ y;
    x = x ^ y;
    cout << "交换后：x=" << x << ", y=" << y << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int a = 9;
    cout << "~a = " << (~a) << endl;  // -10

    int b = -5;
    cout << "~b = " << (~b) << endl;  // 4

    return 0;
}
